.darma-loader-uiverse-blackhole-orbit-text {
  display: flex;
  width: 8rem;
  height: 8rem;
  justify-content: center;
  align-items: center;
  position: relative;
  flex-direction: column;
}

.darma-loader-uiverse-blackhole-orbit-text__curve {
width: 150%;
height: 150%;
position: absolute;
animation: darma-loader-uiverse-blackhole-orbit-text-rotate 8s linear infinite;
fill: transparent;
}

.darma-loader-uiverse-blackhole-orbit-text__curve text {
letter-spacing: 20px;
text-transform: uppercase;
font: 1.5em "Fira Sans", sans-serif;
fill: white;
filter: drop-shadow(0 2px 8px black);
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole {
z-index: 0;
display: flex;
position: absolute;
width: 8rem;
height: 8rem;
align-items: center;
justify-content: center;
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole-circle {
z-index: 0;
display: flex;
width: 100%;
height: 100%;
border-radius: 50%;
background: radial-gradient(circle at center, black 25%, white 35%, white 100%);
box-shadow: 0px 0px 2rem var(--loader-secondary-color, #c2babb);
align-items: center;
justify-content: center;
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole-circle::after {
z-index: 0;
position: absolute;
content: "";
display: flex;
width: 100%;
height: 100%;
border-radius: 50%;
border: 4px solid white;
background: radial-gradient(circle at center, black 35%, white 60%, white 100%);
box-shadow: 0px 0px 4rem var(--loader-secondary-color, #c2babb);
align-items: center;
justify-content: center;
filter: blur(4px);
animation: darma-loader-uiverse-blackhole-orbit-text-pulseAnimation linear infinite 2s alternate-reverse;
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole-circle::before {
z-index: 1;
content: "";
display: flex;
width: 4rem;
height: 4rem;
border: 2px solid var(--loader-color, #ffffff);
box-shadow: 3px 3px 10px var(--loader-secondary-color, #c2babb), inset 0 0 1rem var(--loader-color, #ffffff);
border-radius: 50%;
top: 5rem;
filter: blur(0.5px);
animation: darma-loader-uiverse-blackhole-orbit-text-rotate linear infinite 3s;
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole-disc {
position: absolute;
z-index: 0;
display: flex;
width: 5rem;
height: 10rem;
border-radius: 50%;
background: radial-gradient(circle at center, var(--loader-color, #ffffff) 80%, #353535 90%, white 100%);
filter: blur(1rem) brightness(130%);
border: 1rem solid white;
box-shadow: 0px 0px 3rem #d7c4be;
transform: rotate3d(1, 1, 1, 220deg);
animation: darma-loader-uiverse-blackhole-orbit-text-pulseAnimation2 linear infinite 2s alternate-reverse;
justify-content: center;
align-items: center;
}

.darma-loader-uiverse-blackhole-orbit-text__blackhole-disc::before {
content: "";
position: absolute;
z-index: 0;
display: flex;
width: 5rem;
height: 10rem;
border-radius: 50%;
background: radial-gradient(circle at center, var(--loader-color, #ffffff) 80%, #353535 90%, white 100%);
filter: blur(2rem);
border: 1rem solid white;
box-shadow: 0px 0px 4rem #d7c4be;
animation: darma-loader-uiverse-blackhole-orbit-text-pulseAnimation linear infinite 2s alternate-reverse;
}

@keyframes darma-loader-uiverse-blackhole-orbit-text-rotate {
0% {
transform: rotate(0deg);
}

100% {
transform: rotate(360deg);
}
}

@keyframes darma-loader-uiverse-blackhole-orbit-text-pulseAnimation {
0% {
box-shadow: 0px 0px 3rem var(--loader-secondary-color, #c2babb);
transform: scale(1);
}

100% {
box-shadow: 0px 0px 4rem var(--loader-secondary-color, #c2babb);
transform: scale(1.04);
}
}

@keyframes darma-loader-uiverse-blackhole-orbit-text-pulseAnimation2 {
0% {
box-shadow: 0px 0px 3rem var(--loader-secondary-color, #c2babb);
transform: rotate3d(1, 1, 1, 220deg) scale(1);
}

100% {
box-shadow: 0px 0px 4rem var(--loader-secondary-color, #c2babb);
transform: rotate3d(1, 1, 1, 220deg) scale(.95);
}
}

